1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const parseKey = (key: string): Cell => key.split(",").map(Number) as Cell;
6	
7	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
8	  [-1, -1], [-1, 0], [-1, 1],
9	  [ 0, -1],          [ 0, 1],
10	  [ 1, -1], [ 1, 0], [ 1, 1],
11	];
12	
13	const neighborsOf = ([x, y]: Cell): Array<Cell> =>
14	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	
16	export function nextGeneration(cells: Array<Cell>): Array<Cell> {
17	  const liveSet = new Set(cells.map(cellKey));
18	  const neighborCounts = new Map<string, number>();
19	
20	  for (const cell of cells) {
21	    for (const neighbor of neighborsOf(cell)) {
22	      const key = cellKey(neighbor);
23	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
24	    }
25	  }
26	
27	  const result: Array<Cell> = [];
28	  for (const [key, count] of neighborCounts) {
29	    const survives = liveSet.has(key) && count === 2;
30	    const bornOrSurvives = count === 3;
31	    if (survives || bornOrSurvives) {
32	      result.push(parseKey(key));
33	    }
34	  }
35	  return result;
36	}
37

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor - underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block still-life unchanged (each cell has 3 neighbors)", () => {
15	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const expected: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
17	    const result = nextGeneration(input);
18	    expect(result).toHaveLength(expected.length);
19	    expect(result).toEqual(expect.arrayContaining(expected));
20	  });
21	  it("should oscillate a horizontal blinker into a vertical blinker", () => {
22	    const input: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
23	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
24	    const result = nextGeneration(input);
25	    expect(result).toHaveLength(expected.length);
26	    expect(result).toEqual(expect.arrayContaining(expected));
27	  });
28	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
29	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
30	    const expected: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    const result = nextGeneration(input);
32	    expect(result).toHaveLength(expected.length);
33	    expect(result).toEqual(expect.arrayContaining(expected));
34	  });
35	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
36	    const input: Array<[number, number]> = [
37	      [0, 0], [1, 0], [2, 0],
38	      [0, 1], [1, 1], [2, 1],
39	      [0, 2], [1, 2], [2, 2],
40	    ];
41	    const result = nextGeneration(input);
42	    expect(result).not.toContainEqual([1, 1]);
43	  });
44	  it("should support negative coordinates on the infinite grid", () => {
45	    const input: Array<[number, number]> = [[-5, -5], [-5, -4], [-5, -3]];
46	    const expected: Array<[number, number]> = [[-6, -4], [-5, -4], [-4, -4]];
47	    const result = nextGeneration(input);
48	    expect(result).toHaveLength(expected.length);
49	    expect(result).toEqual(expect.arrayContaining(expected));
50	  });
51	});
