export function nextGeneration(cells: Array<Cell>): Array<Cell> {
  const liveSet = new Set(cells.map(cellKey));
  const neighborCounts = new Map<string, number>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
    }
  }

  const result: Array<Cell> = [];
  for (const [key, count] of neighborCounts) {
    const survives = liveSet.has(key) && count === 2;
    const bornOrSurvives = count === 3;
    if (survives || bornOrSurvives) {
      result.push(parseKey(key));
    }
  }
  return result;
}

